  ('heelevel3-29a002de-moex-00051', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-114-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'single_choice', '下列何者非為民法上之物權？', '["不動產役權", "典權", "權利質權", "遺產之使用收益權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "56525ec09aaf", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "227", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00052', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-114-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'single_choice', '下列關於不動產所有權之取得或移轉，何者應辦理登記，始發生效力？', '["私人土地之徵收", "法院強制執行拍賣債務人名下之土地，而由他人拍定", "私人拋棄其土地所有權", "私人蓋好房屋"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "56525ec09aaf", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "227", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00053', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-114-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'single_choice', '甲男乙女為夫妻，甲竟與乙之姪女丙發生姦情。乙訴請判決離婚，判決確定之一個月後，甲與丙 結婚。下列敘述，何者正確？', '["甲丙違反待婚期間之限制，其婚姻得撤銷", "甲丙違反相姦婚禁止之規定，其婚姻得撤銷", "甲丙違反近親結婚之限制，其婚姻無效", "甲丙並未違反規定，其婚姻有效"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "56525ec09aaf", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "227", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00054', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-114-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'single_choice', '遺產分割後，其未清償之被繼承人之債務，移歸一定之人承受，或劃歸各繼承人分擔，如經債權 人同意者，各繼承人得免除何種責任？', '["連帶保證", "連帶責任", "連帶債權", "侵權責任"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "56525ec09aaf", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "227", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00055', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-114-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'single_choice', '甲、乙為夫妻，無子女。甲之父母均已死亡，甲有兄弟丙、丁二人。甲生前曾向丙借款新臺幣（下 同）40萬元，尚未清償。甲死亡時，留有遺產200萬元。遺產分割時，丙可分得多少財產？', '["60萬元", "70萬元", "80萬元", "90萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "56525ec09aaf", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "227", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00056', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-114-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'single_choice', '甲男乙女於民國112年1月間結婚，甲於結婚前，有勞力所得新臺幣（下同）60萬元。下列關於 夫妻財產之敘述，何者正確？', '["設甲乙約定採共同財產制，甲勞力所得之60萬元，由甲乙分別共有", "設甲乙約定採分別財產制，甲勞力所得之60萬元，由甲乙分別共有", "設甲乙未約定夫妻財產制，甲勞力所得之60萬元，由甲乙公同共有", "設甲乙約定採勞力所得共同財產制，甲勞力所得之60萬元，由甲單獨所有"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "56525ec09aaf", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "227", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00057', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-114-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'single_choice', '未婚之甲女與乙男發生性關係後懷孕並產下丙。丙成年後找到乙，要求乙為認領。乙表示其生活 窮困，若丙願扶養，則乙願認領。下列敘述，何者正確？', '["認領後，如丙確有受扶養必要，乙有扶養能力，乙應扶養丙", "認領後，如乙確實無謀生能力但尚非無法維持生活，丙仍應扶養乙", "認領後，如乙確有受扶養必要，甲丙應共同扶養乙", "認領經雙方意思表示合致成立，乙所附條件為有效"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "56525ec09aaf", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "227", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00058', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-114-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'single_choice', '甲乙為夫妻，生有A、B二子，並收養C為養女。乙於民國108年間死亡。今甲死亡，下列敘述， 何者正確？', '["A如對甲有重大之虐待或侮辱情事，經B及C共同表示A不得繼承；A則喪失其對甲之繼承權", "A及B於乙死亡後，否認C之繼承資格，並排除其對繼承財產之占有，C自知悉其得繼承之 時起2年間，得行使遺產酌給請求權", "B如有以詐欺或脅迫，使甲為關於繼承遺囑之情事，B則喪失其對甲之繼承權。但經甲宥恕者， 其繼承權不喪失", "甲如未立遺囑，C之應繼分為甲遺產之五分之一，A及B之應繼分各為甲遺產之五分之二"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "56525ec09aaf", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "227", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00059', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-113-916530c6', 'sub-heelevel3-29a002de-01', NULL, 'essay', '甲新買了一台重機，為顯現其壓車過彎的功力，邀集乙、丙、丁等好友
在週末假日到阿里山道路上飆車，因一群人競速影響往來行駛車輛，路
人遂通知警察。警察到場後，甲不理取締，加速衝撞警察離去，造成其
中一位警察受傷。因警方已記下甲車牌號碼，一日後依紀錄找到甲，開
罰單並吊扣其牌照。甲心想新的重機不開可惜，心生一計，影印牌照，
在繳交牌照後，黏貼於重機原掛牌照處，仍騎車上路。請問甲的行為如
何論處？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "80f7e5b07803", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "1014", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00060', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-113-916530c6', 'sub-heelevel3-29a002de-01', NULL, 'essay', '甲至夜店飲酒，見乙落單，且喝到斷片，不省人事，假藉幫忙叫車送乙
回家，將乙帶回住處。趁機脫下乙的衣褲性交，並將性交過程錄影。第
二日乙清醒，知道自己前開情形，揚言告甲。甲拿出性交影片宣稱，如
果乙敢提告，甲就將前開性交影片上傳社群媒體。乙因心裡害怕遂未告
甲，但甲仍然將影片上傳其臉書，誇耀其性能力。請問甲的行為如何論
處？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "80f7e5b07803", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "1014", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL)
